#include<bits/stdc++.h>
using namespace std;
long long n,cnt,maxh,maxx,f1[200010],f2[200010];
double sum,g1[200010],g2[200010];
struct node
{
    long long t,h,v;
}s[200010];
bool cmpt(node a,node b)
{
    return a.t<b.t;
}
bool cmph(node a,node b)
{
    return (a.h==b.h?(a.t<b.t):(a.h>b.h));
}
set<long long> st;
map<long long,long long> id;
long long max1[200010];
double cnt1[200010];
void clear(long long x,long long l,long long r)
{
    if(max1[x]==0)
    {
        return;
    }
    max1[x]=0;
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    clear(x<<1,l,mid);
    clear(x<<1|1,mid+1,r);
}
void update(long long x,long long l,long long r,long long p,long long v,double v2)
{
    if(l>p||r<p)
    {
        return;
    }
    if(l==r)
    {
        if(max1[x]<v)
        {
            max1[x]=v;
            cnt1[x]=0;
        }
        if(max1[x]==v)
        {
            cnt1[x]+=v2;
        }
        return;
    }
    long long mid=(l+r)>>1;
    update(x<<1,l,mid,p,v,v2);
    update(x<<1|1,mid+1,r,p,v,v2);
    max1[x]=max(max1[x<<1],max1[x<<1|1]);
    cnt1[x]=0;
    if(max1[x]==max1[x<<1])
    {
        cnt1[x]+=cnt1[x<<1];
    }
    if(max1[x]==max1[x<<1|1])
    {
        cnt1[x]+=cnt1[x<<1|1];
    }
}
long long query(long long x,long long l,long long r,long long u,long long v,double&val)
{
    if(l>v||r<u)
    {
        val=0;
        return 0;
    }
    if(u<=l&&r<=v)
    {
        val=cnt1[x];
        return max1[x];
    }
    long long mid=(l+r)>>1;
    double cntl=0,cntr=0;
    long long al=query(x<<1,l,mid,u,v,cntl);
    long long ar=query(x<<1|1,mid+1,r,u,v,cntr);
    if(mid>=u&&max(al,ar)==al)
    {
        val+=cntl;
    }
    if(mid<v&&max(al,ar)==ar)
    {
        val+=cntr;
    }
    return max(al,ar);
}
void cdq(long long f[],double g[],long long l,long long r)
{
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    sort(s+l,s+1+r,cmpt);
    cdq(f,g,l,mid);
    sort(s+l,s+1+mid,cmph);
    sort(s+1+mid,s+1+r,cmph);
    clear(1,1,n);
    for(long long i=l,j=mid+1;j<=r;j++)
    {
        while(i<=mid&&s[i].h>=s[j].h)
        {
            update(1,1,n,s[i].v,f[s[i].t],g[s[i].t]);
            i++;
        }
        double cnt2=0;
        long long t=query(1,1,n,s[j].v,n,cnt2);
        if(t==0)
        {
            continue;
        }
        if(f[s[j].t]<t+1)
        {
            f[s[j].t]=t+1;
            g[s[j].t]=0;
        }
        if(f[s[j].t]==t+1)
        {
            g[s[j].t]+=cnt2;
        }
    }
    cdq(f,g,mid+1,r);
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&s[i].h,&s[i].v);
        s[i].t=i;
        st.insert(s[i].v);
        maxh=max(maxh,s[i].h);
    }
    for(long long i:st)
    {
        id[i]=++cnt;
    }
    for(long long i=1;i<=n;i++)
    {
        s[i].v=id[s[i].v];
    }
    for(long long i=1;i<=n;i++)
    {
        f1[i]=f2[i]=1;
        g1[i]=g2[i]=1.0;
    }
    cdq(f1,g1,1,n);
    for(long long i=1;i<=n;i++)
    {
        maxx=max(maxx,f1[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        if(f1[i]==maxx)
        {
            sum+=g1[i];
        }
    }
    printf("%lld\n",maxx);
    for(long long i=1;i<=n;i++)
    {
        s[i].t=n-s[i].t+1;
        s[i].h=maxh-s[i].h+1;
        s[i].v=cnt-s[i].v+1;
    }
    cdq(f2,g2,1,n);
    for(long long i=1;i<=n;i++)
    {
        if(f1[i]+f2[n-i+1]-1!=maxx)
        {
            printf("0.00000 ");
        }
        else
        {
            printf("%.5lf ",g1[i]*g2[n-i+1]/sum);
        }
    }
    return 0;
}
